paper_content.figures:
[
  {
    "figure_id": "Figure 1",
    "caption": "Sequence alignment of selected regions within the EGFR and B-Raf kinase domains. Depiction of each type of EGFR mutation in human NSCLC. EGFR (gb:X00588) mutations in NSCLC tumors are highlighted in yellow. B-Raf (gb:M95712) mutations in multiple tumor types are highlighted in blue. Asterisks denote residues conserved between EGFR and B-Raf.",
    "panels": [
      {
        "panel": "A",
        "description": "L858R mutations in activation loop. Shows sequence alignment with EGFR L858R mutation (KTPQHVKITDFGRAKLLGAEEKEYH, position 870) compared to wild-type EGFR and BRAF."
      },
      {
        "panel": "B",
        "description": "G719S mutant in P-loop. Shows sequence alignment with G719S mutation (position 733) in the P-loop region."
      },
      {
        "panel": "C",
        "description": "Deletion mutants in EGFR exon 19. Shows Del-1 through Del-5 deletion variants at position 765, with various in-frame deletions affecting codons 746-759."
      }
    ]
  },
  {
    "figure_id": "Figure 2",
    "caption": "Positions of missense mutations G719S and L858R and the Del-1 deletion in the three-dimensional structure of the EGFR kinase domain. The activation loop is shown in yellow, the P-loop is in blue, and the C-lobe and N-lobe are as indicated. The residues targeted by mutation or deletion are highlighted in red. The Del-1 mutation targets the residues ELREA in codons 746 to 750.",
    "description": "3D protein structure showing EGFR kinase domain with labeled regions: activation loop (yellow), P-loop (blue), C-lobe, N-lobe. Key mutation sites G719 and L858 are indicated, along with the ELREA deletion region."
  },
  {
    "figure_id": "Figure 3",
    "caption": "A lung adenocarcinoma cell line with EGFR receptor mutation is sensitive to growth and signaling inhibition by gefitinib.",
    "panels": [
      {
        "panel": "A",
        "description": "Cell viability assay showing dose-response curves for four cell lines (H1781, H1666, H441, H3255) treated with gefitinib. X-axis: gefitinib concentration (μM) from 0.001 to 10. Y-axis: Cell viability (% of control) from 0 to 120. H3255 shows dramatic sensitivity with IC50 of 0.04 μM (40 nM), approximately 50-fold more sensitive than other cell lines which have IC50 >2 μM."
      },
      {
        "panel": "B",
        "description": "Western blot analysis showing inhibition of EGFR phosphorylation and downstream signaling. Cell lines H1781, H1666, H441, H3255 treated with gefitinib at 0, 0.1, 1.0, 10.0 μM for 24 hours. Proteins analyzed: p-EGFR, EGFR, p-ERK1/2, ERK1/2, p-AKT, AKT. H3255 (L858R mutant) shows complete inhibition of p-EGFR, p-ERK1/2, and p-AKT at 0.1 μM, while wild-type cell lines require ~10 μM for comparable inhibition."
      }
    ]
  }
]

